INSERT INTO dictionary_definitions (word_id, part_of_speech, definition_en, definition_zh, order_index, source_type) VALUES
  ('ability','noun','the power, skill, or capacity to do something','能力；才能',0,'original'),
  ('advice','noun','guidance or recommendations offered about future action','建议；忠告',0,'original'),
  ('benefit','noun','an advantage or good result gained from something','益处；好处；利益',0,'original'),
  ('connect','verb','to join or link two or more things together','连接；联系；接通',0,'original'),
  ('enjoy','verb','to get pleasure or satisfaction from something','享受；喜爱；乐于',0,'original'),
  ('explain','verb','to make something clear or easy to understand by describing it in detail','解释；说明；阐述',0,'original'),
  ('purpose','noun','the reason for which something is done or for which something exists','目的；用途；意图',0,'original'),
  ('result','noun','something that happens or exists because of an action, effort, or event','结果；成果；导致',0,'original'),
  ('suggest','verb','to put forward an idea or plan for someone to consider','建议；提出；暗示',0,'original'),
  ('understand','verb','to know or grasp the meaning, importance, or nature of something','理解；明白；懂得',0,'original'),
  ('apply','verb','to make use of something, or to make a formal request for something','申请；应用；适用',0,'original'),
  ('challenge','noun','a situation that requires great effort and tests your abilities','挑战；困难；质疑',0,'original'),
  ('concentrate','verb','to focus your full attention or effort on something','集中（注意力）；专注；专心',0,'original'),
  ('consequence','noun','a result or effect of an action or situation, often negative or unintended','后果；结果；重要性',0,'original'),
  ('control','verb','the power to direct or influence how something works or behaves','控制；管制；掌管',0,'original'),
  ('current','adjective','happening or existing now, at the present time','当前的；现在的；（水、电）流',0,'original'),
  ('depend','verb','to need something for support, or to be determined by something','依赖；取决于；信赖',0,'original'),
  ('develop','verb','to grow or cause something to grow more advanced, larger, or stronger','发展；开发；培养',0,'original'),
  ('evaluate','verb','to assess the value, quality, or importance of something carefully','评估；评价；鉴定',0,'original'),
  ('expect','verb','to believe that something will happen or that someone will do something','期望；预期；料想',0,'original'),
  ('factor','noun','one of the elements that contributes to a particular result or situation','因素；要素；因数',0,'original'),
  ('focus','verb','to direct attention or effort toward a particular point or task','专注；集中；焦点',0,'original'),
  ('involve','verb','to include someone or something as a necessary part','包含；涉及；使参与',0,'original'),
  ('method','noun','a particular way of doing something, especially a systematic or established one','方法；方式；途径',0,'original'),
  ('obtain','verb','to get or acquire something through effort or a formal request','获得；取得；得到',0,'original'),
  ('organize','verb','to arrange things or activities in a structured and efficient way','组织；整理；安排',0,'original'),
  ('process','noun','a series of actions or steps taken in order to achieve a particular result','过程；流程；处理',0,'original'),
  ('require','verb','to need something as a necessary condition or as essential','需要；要求；规定',0,'original'),
  ('respond','verb','to say or do something as a reaction to what someone has said or done','回应；反应；答复',0,'original'),
  ('support','verb','to give help, encouragement, or approval to someone or something','支持；帮助；资助',0,'original'),
  ('allocate','verb','to distribute resources, tasks, or responsibilities among people or uses','分配；拨给；分派',0,'original'),
  ('assume','verb','to accept something as true without proof, or to take on a role or responsibility','假设；承担；采取',0,'original'),
  ('circumstance','noun','a condition or fact that affects a situation, decision, or event','情况；环境；境遇',0,'original'),
  ('complex','adjective','consisting of many different and connected parts; not easy to understand or deal with','复杂的；难以理解的；综合体',0,'original'),
  ('conclude','verb','to come to a judgment or decision after reasoning or investigation','得出结论；结束；断定',0,'original'),
  ('confirm','verb','to make certain that something is true or that something will happen','确认；证实；批准',0,'original'),
  ('context','noun','the circumstances or setting that surround an event, statement, or idea','背景；语境；上下文',0,'original'),
  ('define','verb','to state exactly what something means or to describe its essential qualities','定义；阐明；界定',0,'original'),
  ('establish','verb','to set up, create, or confirm something on a firm or permanent basis','建立；确立；证实',0,'original'),
  ('extent','noun','the degree, range, or scope to which something applies or exists','程度；范围；限度',0,'original'),
  ('facilitate','verb','to make something easier or help it happen more smoothly','促进；使便利；帮助实现',0,'original'),
  ('imply','verb','to suggest something without saying it directly or explicitly','暗示；意味着；含有…的意思',0,'original'),
  ('indicate','verb','to point out, show, or suggest something as likely or true','表明；指出；标示',0,'original'),
  ('interpret','verb','to explain or understand something in a particular way','解释；理解；诠释；口译',0,'original'),
  ('investigate','verb','to examine something carefully to find out the truth or facts','调查；研究；审查',0,'original'),
  ('outcome','noun','the way something ends; the result produced by an action or process','结果；成效；结局',0,'original'),
  ('predict','verb','to say what you think will happen in the future based on available information','预测；预言；预料',0,'original'),
  ('principle','noun','a fundamental rule, belief, or law that governs behavior or explains how something works','原则；原理；准则',0,'original'),
  ('specific','adjective','clearly defined or identified; relating to a particular thing and not general','具体的；特定的；明确的',0,'original'),
  ('valid','adjective','based on sound reasoning; legally or officially acceptable','有效的；有根据的；合法的',0,'original'),
  ('ambiguous','adjective','having more than one possible meaning; open to different interpretations','模糊的；有歧义的；不明确的',0,'original'),
  ('controversy','noun','a prolonged public argument or disagreement, especially about a sensitive subject','争议；争论；争辩',0,'original'),
  ('eliminate','verb','to completely remove or get rid of something unwanted','消除；淘汰；排除',0,'original'),
  ('endorse','verb','to officially support or approve of someone or something publicly','认可；支持；背书；代言',0,'original'),
  ('inevitable','adjective','certain to happen and impossible to avoid or prevent','不可避免的；必然的；确定的',0,'original'),
  ('inhibit','verb','to prevent or slow down a process, action, or ability','抑制；阻碍；妨碍',0,'original'),
  ('implicit','adjective','implied or understood though not directly stated; complete and unquestioned','隐含的；不言而喻的；含蓄的',0,'original'),
  ('integrate','verb','to combine parts into a whole, or to include someone fully in a group or system','整合；融合；使融入',0,'original'),
  ('notion','noun','a belief, idea, or concept, often one that is vague or uncertain','概念；想法；观念',0,'original'),
  ('objective','adjective','not influenced by personal feelings; based on facts rather than opinions','客观的；公正的；目标',0,'original'),
  ('paradox','noun','a statement or situation that seems contradictory but may reveal a deeper truth','悖论；自相矛盾的事物；似非而是的论点',0,'original'),
  ('regulate','verb','to control or supervise something by means of rules or procedures','管控；调节；监管',0,'original'),
  ('rhetoric','noun','the art of effective or persuasive speaking and writing; language designed to impress','修辞；措辞；夸夸其谈',0,'original'),
  ('scrutiny','noun','careful and detailed examination or investigation of something','仔细审查；严格检查；详细审视',0,'original'),
  ('sustain','verb','to keep something going over a period of time; to maintain or support','维持；持续；支撑；承受',0,'original'),
  ('tangible','adjective','clearly perceived and definite; something real and concrete rather than vague','有形的；切实的；可感知的',0,'original'),
  ('vulnerable','adjective','susceptible to being harmed, attacked, or negatively affected','脆弱的；易受伤害的；易受影响的',0,'original'),
  ('ambivalent','adjective','having mixed or conflicting feelings about something or someone at the same time','矛盾的；有两种情感的；态度不明的',0,'original'),
  ('articulate','adjective','able to express ideas clearly and effectively; (verb) to express or explain clearly','口齿清晰的；表达流畅的；表达清楚',0,'original'),
  ('meticulous','adjective','showing great care and precision; giving close attention to every detail','细致的；一丝不苟的；极其谨慎的',0,'original'),
  ('nuanced','adjective','showing subtle distinctions or variations in meaning, expression, or understanding','细致入微的；有细微差别的；含义微妙的',0,'original'),
  ('pragmatic','adjective','dealing with things practically and realistically rather than theoretically','务实的；实际的；注重实效的',0,'original'),
  ('profound','adjective','very deep, intense, or having great significance and importance','深刻的；意义深远的；渊博的',0,'original'),
  ('verbose','adjective','using more words than necessary; long-winded in speech or writing','冗长的；啰嗦的；用词过多的',0,'original');
INSERT INTO dictionary_examples (word_id, sentence_en, sentence_zh, order_index, source_type) VALUES
  ('ability','She has the ability to solve complex problems under pressure.','她有在压力下解决复杂问题的能力。',0,'original'),
  ('advice','His advice helped me make the right career decision.','他的建议帮助我做出了正确的职业选择。',0,'original'),
  ('benefit','Regular exercise brings many benefits to your health.','定期锻炼对健康有很多好处。',0,'original'),
  ('connect','The bridge connects the two islands.','这座桥把两个岛连接起来。',0,'original'),
  ('enjoy','I enjoy listening to music while studying.','我喜欢边学习边听音乐。',0,'original'),
  ('explain','The teacher explained the concept using simple examples.','老师用简单的例子解释了这个概念。',0,'original'),
  ('purpose','The purpose of this meeting is to share our progress.','本次会议的目的是分享我们的进展。',0,'original'),
  ('result','The hard work resulted in excellent test scores.','努力学习带来了优秀的考试成绩。',0,'original'),
  ('suggest','She suggested we take a different approach to the problem.','她建议我们用不同的方法解决这个问题。',0,'original'),
  ('understand','It takes time to fully understand a new language.','完全掌握一门新语言需要时间。',0,'original'),
  ('apply','You need to apply what you learn in class to real situations.','你需要把课堂上学到的知识应用到实际情况中。',0,'original'),
  ('challenge','Learning a new language is a challenge worth taking.','学习一门新语言是一项值得接受的挑战。',0,'original'),
  ('concentrate','It''s hard to concentrate when there is too much noise.','当噪音太大时，很难集中注意力。',0,'original'),
  ('consequence','The consequences of climate change affect everyone on Earth.','气候变化的后果影响到地球上的每一个人。',0,'original'),
  ('control','Self-control is an important skill in learning.','自我控制是学习中的一项重要技能。',0,'original'),
  ('current','What is your current level of English proficiency?','您当前的英语水平如何？',0,'original'),
  ('depend','Your success depends on how consistently you practice.','你的成功取决于你练习的持续程度。',0,'original'),
  ('develop','Reading widely helps you develop a rich vocabulary.','广泛阅读有助于你培养丰富的词汇量。',0,'original'),
  ('evaluate','Students must evaluate both sides of an argument before writing.','学生在写作前必须评估论点的两面。',0,'original'),
  ('expect','I expect to finish the project by the end of this week.','我预计在本周末前完成这个项目。',0,'original'),
  ('factor','Motivation is a key factor in successful language learning.','积极性是成功学习语言的关键因素。',0,'original'),
  ('focus','Try to focus on one task at a time for better results.','尝试一次专注于一项任务，以获得更好的效果。',0,'original'),
  ('involve','The project involves reading, writing, and speaking tasks.','该项目涉及阅读、写作和口语任务。',0,'original'),
  ('method','The spaced repetition method is effective for memorizing vocabulary.','间隔重复法对于记忆词汇非常有效。',0,'original'),
  ('obtain','She obtained her certificate after years of dedicated study.','经过多年的刻苦学习，她获得了证书。',0,'original'),
  ('organize','Organize your study schedule to balance all subjects equally.','合理安排学习计划，平衡各科目的学习时间。',0,'original'),
  ('process','Learning vocabulary is a gradual process that requires patience.','学习词汇是一个需要耐心的渐进过程。',0,'original'),
  ('require','Fluency requires consistent practice over months and years.','流利程度需要数月乃至数年持续的练习。',0,'original'),
  ('respond','How did she respond to the difficult question?','她如何回应这个难题？',0,'original'),
  ('support','Good friends support each other through difficult times.','好朋友在困难时期互相支持。',0,'original'),
  ('allocate','We need to allocate more time to vocabulary review each day.','我们每天需要分配更多时间复习词汇。',0,'original'),
  ('assume','Don''t assume you know a word''s meaning just from its spelling.','不要仅凭拼写就假设你知道一个单词的含义。',0,'original'),
  ('circumstance','Under certain circumstances, learning a language faster is possible.','在某些情况下，更快地学习一门语言是可能的。',0,'original'),
  ('complex','Grammar rules can be complex, but patterns make them easier.','语法规则可能很复杂，但规律性使它们更容易理解。',0,'original'),
  ('conclude','The researcher concluded that immersion speeds up language acquisition.','研究人员得出结论：沉浸式学习可以加速语言习得。',0,'original'),
  ('confirm','Please confirm your appointment at least one day in advance.','请至少提前一天确认您的预约。',0,'original'),
  ('context','Understanding a word''s context helps you use it correctly.','理解单词的语境有助于你正确使用它。',0,'original'),
  ('define','A dictionary defines words by giving their meaning and usage.','词典通过给出单词的含义和用法来对其进行定义。',0,'original'),
  ('establish','Establish a daily reading habit to build your vocabulary naturally.','养成每天阅读的习惯，自然地扩大词汇量。',0,'original'),
  ('extent','To what extent do flashcards help you retain new vocabulary?','抽认卡在多大程度上有助于你记住新词汇？',0,'original'),
  ('facilitate','Technology can facilitate language learning through instant feedback.','技术可以通过即时反馈来促进语言学习。',0,'original'),
  ('imply','His silence implied that he disagreed with the decision.','他的沉默暗示他不同意这个决定。',0,'original'),
  ('indicate','The data indicates a clear improvement in reading comprehension.','数据表明阅读理解能力有明显提升。',0,'original'),
  ('interpret','Different readers can interpret the same text in different ways.','不同的读者可以用不同的方式解读同一文本。',0,'original'),
  ('investigate','Scientists investigate how children naturally acquire language.','科学家们研究儿童如何自然习得语言。',0,'original'),
  ('outcome','The outcome of the test surprised everyone — all students passed.','考试结果让所有人感到惊讶——所有学生都通过了。',0,'original'),
  ('predict','Can you predict which vocabulary items will appear on the exam?','你能预测哪些词汇会出现在考试中吗？',0,'original'),
  ('principle','The principle of spaced repetition improves long-term memory.','间隔重复原理有助于改善长期记忆。',0,'original'),
  ('specific','Be specific about which words you want to review today.','明确说出你今天想复习哪些单词。',0,'original'),
  ('valid','Your observation is valid — consistency is key to language learning.','你的观察是有道理的——坚持是语言学习的关键。',0,'original'),
  ('ambiguous','The instructions were ambiguous, so students interpreted them differently.','指示内容含糊不清，所以学生们的理解各不相同。',0,'original'),
  ('controversy','The new curriculum caused controversy among parents and teachers.','新课程在家长和教师中引发了争议。',0,'original'),
  ('eliminate','You can eliminate confusion by reviewing vocabulary daily.','通过每天复习词汇，你可以消除困惑。',0,'original'),
  ('endorse','Experts endorse spaced repetition as the most effective study technique.','专家们认可间隔重复是最有效的学习技术。',0,'original'),
  ('inevitable','Some mistakes are inevitable when learning a new language.','学习新语言时，某些错误是不可避免的。',0,'original'),
  ('inhibit','Fear of making mistakes can inhibit language learning.','害怕犯错会阻碍语言学习。',0,'original'),
  ('implicit','There is an implicit understanding that students prepare before class.','学生在课前做好准备是一种不言而喻的共识。',0,'original'),
  ('integrate','Try to integrate new vocabulary into your daily conversations.','试着把新词汇融入你的日常对话中。',0,'original'),
  ('notion','He challenged the notion that grammar must be memorized by rules alone.','他挑战了语法必须单靠规则记忆这一观念。',0,'original'),
  ('objective','An objective self-assessment helps identify your weaknesses.','客观的自我评估有助于发现自身的弱点。',0,'original'),
  ('paradox','The language learner''s paradox: the more you study, the more you realize you don''t know.','语言学习者的悖论：你学得越多，越意识到自己还有很多不了解的东西。',0,'original'),
  ('regulate','Schools regulate the use of digital devices to improve student focus.','学校管控数字设备的使用以提高学生的专注度。',0,'original'),
  ('rhetoric','Politicians often use powerful rhetoric to win public support.','政客们经常使用有力的修辞来赢得公众支持。',0,'original'),
  ('scrutiny','Every argument in an essay should be able to withstand scrutiny.','文章中的每个论点都应该经得起仔细检查。',0,'original'),
  ('sustain','Daily practice is the best way to sustain language progress.','每日练习是持续语言进步的最佳方式。',0,'original'),
  ('tangible','She saw tangible improvements in her reading speed after one month.','一个月后，她发现自己的阅读速度有了切实的提升。',0,'original'),
  ('vulnerable','Beginners are often vulnerable to losing motivation early in their studies.','初学者往往容易在学习初期丧失动力。',0,'original'),
  ('ambivalent','She felt ambivalent about leaving her country to study abroad.','她对出国留学感到矛盾，心情复杂。',0,'original'),
  ('articulate','An articulate speaker chooses precise words to convey complex ideas.','一位表达流畅的演讲者会选择精准的词汇来传达复杂的想法。',0,'original'),
  ('meticulous','A meticulous proofreader catches every grammar and spelling mistake.','一位细致的校对员能发现每一个语法和拼写错误。',0,'original'),
  ('nuanced','A nuanced understanding of idioms takes years of exposure to the language.','对习语的细致理解需要多年接触语言的积累。',0,'original'),
  ('pragmatic','A pragmatic learner focuses on the vocabulary they need most immediately.','务实的学习者专注于他们最迫切需要的词汇。',0,'original'),
  ('profound','Learning a second language has a profound impact on how you see the world.','学习第二语言对你看待世界的方式有着深远的影响。',0,'original'),
  ('verbose','A verbose essay uses too many words to express a simple idea.','一篇冗长的文章用了太多的文字来表达一个简单的想法。',0,'original');
